const body = $input.first().json.body;

const request_id = body.request_id || 'req-' + Date.now().toString(36) + Math.random().toString(36).slice(2,8);
const text = (body.text || '').trim();
const images = Array.isArray(body.images) ? body.images : [];
const task_type = body.task_type || 'auto';

const has_text = text.length > 0;
const has_images = images.length > 0;

return [{
  json: {
    request_id,
    text,
    images,
    task_type,
    has_text,
    has_images,
    trace: []
  }
}];

const input = $input.first().json;
let vision_result = null;
let text_result = null;
const trace = [...input.trace];

const tools_to_call = [];
if (input.has_images) tools_to_call.push('vision');
if (input.has_text) tools_to_call.push('text');
tools_to_call.push('report');
const decision = 'called ' + tools_to_call.join('+') + ' then report';
trace.push({ step: 'orchestrator', decision: decision });

if (input.has_images) {
  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: 'http://localhost:5678/webhook/tool/vision',
      body: { request_id: input.request_id, images: input.images },
      headers: { 'Content-Type': 'application/json' },
      timeout: 60000
    });
    vision_result = resp;
    trace.push({ step: 'tool_call', tool: 'vision_tool', status: 'ok' });
  } catch (e) {
    trace.push({ step: 'tool_call', tool: 'vision_tool', status: 'error', error: e.message });
  }
}

if (input.has_text) {
  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: 'http://localhost:5678/webhook/tool/text',
      body: { request_id: input.request_id, text: input.text },
      headers: { 'Content-Type': 'application/json' },
      timeout: 60000
    });
    text_result = resp;
    trace.push({ step: 'tool_call', tool: 'text_tool', status: 'ok' });
  } catch (e) {
    trace.push({ step: 'tool_call', tool: 'text_tool', status: 'error', error: e.message });
  }
}

return [{
  json: {
    request_id: input.request_id,
    original_input: { text: input.text, images: input.images, task_type: input.task_type },
    vision_result,
    text_result,
    trace
  }
}];
